export interface ShioriProps {
  title: string;
  description: string;
  accent?: string;
  accentSecondary?: string;
}

export const Shiori = ({
  title,
  description,
  accent,
  accentSecondary,
}: ShioriProps) => (
  <div
    style={{
      backgroundColor: "#faf6f1",
      color: "#1a1a1a",
      display: "flex",
      flexDirection: "column",
      height: "100%",
      padding: "80px",
      position: "relative",
      width: "100%",
    }}
  >
    <div
      style={{
        background: `linear-gradient(135deg, ${accent}, ${accentSecondary})`,
        borderRadius: "50%",
        height: "96px",
        width: "96px",
      }}
    />

    <div
      style={{
        alignItems: "center",
        bottom: "80px",
        display: "flex",
        gap: "40px",
        left: "80px",
        position: "absolute",
        right: "80px",
      }}
    >
      <div
        style={{
          display: "flex",
          fontSize: "88px",
          fontWeight: 700,
          letterSpacing: "-0.03em",
          lineHeight: 1,
        }}
      >
        {title}
      </div>

      <div
        style={{
          color: "#8b7e74",
          display: "flex",
          fontSize: "56px",
          fontWeight: 400,
          lineHeight: 1.3,
          maxWidth: "600px",
        }}
      >
        {description}
      </div>
    </div>
  </div>
);

Shiori.previewProps = {
  accent: "#f97316",
  accentSecondary: "#ea580c",
  description: "A beautifully simple read-it-later app",
  title: "Shiori",
} satisfies ShioriProps;
